import{_ as e,o as a,c as t,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小动物- 猫","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 猫.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 猫.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 猫.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"小动物-猫",tabindex:"-1"},[p("小动物- 猫 "),r("a",{class:"header-anchor",href:"#小动物-猫","aria-label":'Permalink to "小动物- 猫"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),s('<h1 id="小动物-猫-1" tabindex="-1">小动物- 猫 <a class="header-anchor" href="#小动物-猫-1" aria-label="Permalink to &quot;小动物- 猫&quot;">​</a></h1><p>猫<br> 无支线随从<br> 250分<br> 动物种类：猫科动物<br> 猫（拉丁学名：Felis silvestris catus），是食肉目猫科猫属 的脊索动物。猫体型小，体色由蓝灰色到棕黄色，体型瘦削，身长0.3-0.5米，全身毛被密而柔软，锁骨小，吻部短，眼睛圆，颈部粗壮，四肢较短，足下有数个球形肉垫；舌面被有角质层的丝状钩形乳突。猫雌雄性个体彼此相似，仅雄性头部粗圆，个体大些。猫的繁殖与生育期长达一生，寿命有12-17年。<br> 随从外貌：在购买后需要自己去选择一种已知的猫种进行选择外貌，选择后自己描述在该处。<br> 基础外貌：5<br> 基础体型：1</p><p>随从属性：<br> 生理属性<br> 力量：1<br> 敏捷：5<br> 耐力：3<br> 心智属性<br> 智力：1<br> 感知：3<br> 决心：1<br> 互动属性<br> 风度：5<br> 操控：3<br> 沉着：1</p><p>技能<br> 生理系<br> 运动3<br> 专业：反射3 跳跃1<br> 求生1<br> 专业：强韧1<br> 射击1<br> 专业：<br> 武技1<br> 专业：爪击1</p><p>心智系<br> 学识1<br> 专业：爪子精通1<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注1<br> 专业：意志1</p><p>互动系<br> 洞察3<br> 专业：侦查3<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【1】+敏捷【5】+体积【1】+每1点敏捷上的附加获得3移动速度）=7<br> 先攻 （敏捷【5】+沉着【1】）= 6<br> 防御 （敏捷感知的平均值【4】+较高者的附加成功【】）=4<br> 生命值 （耐力【3】+体积【1】+耐力附加【 】×5）=4<br> 意志力池 （决心【1】+沉着【1】+决心附加【 】×2）=2<br> 意志 （决心【1】+专注+意志【2】）= 3<br> 反射 （敏捷【5】+运动+反射【6】）= 11+1<br> 强韧 （耐力【3】+生存+强韧【2】）= 5<br> 侦查 （感知【3】+洞察+侦查【6】）= 9+1<br> 敏感范围 （感知【3】*20米+感知上的附加成功【 】*20米）=60米</p><p>攻击预设：4<br> 基础DP：1（力量）+1（武技）+1（爪击）+1（爪子精通）=4<br> 非常态项：<br> 破防效果：<br> 附加成功：<br> 非常态项：<br> 攻击特殊效果：</p><p>防御预设：<br> 基础防御：4<br> 附加成功：无<br> 额外效果：<br> 防御类型：<br> 附加成功：<br> 额外效果：</p><p>豁免项：<br> 意志豁免：3<br> 附加成功：<br> 反射豁免：11<br> 附加成功：1<br> 强韧豁免：5<br> 附加成功：</p><p>免疫项：</p><p>专长：</p><p>装备位：<br> 头部-面具/头盔（会被猫猫带在头上但是因为脸部无法带面具所以一般面具无法佩戴）<br> 颈部-护符 （会变成项链吊坠项圈这种在猫猫的身上）<br> 上肢-躯干 （会被当做衣服穿在猫猫的身上）<br> 肩部-斗篷 （会在脖子上，但是会跟颈部装备产生冲突）<br> 上肢-爪子 （给爪子上特殊的武装，但是不能持握武器）<br> 手部-手腕 （给猫猫的四条腿上挂上腕带类似，戴上一个可以选择四条腿都有一样的画风，但是依旧只有一个装备位）<br> 下肢-鞋袜 （给猫猫的爪子穿上鞋袜但是因此会跟爪子产生冲突）</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=e(n,[["render",o]]);export{f as __pageData,m as default};
